/* helper:(i0[31],i1[72],i2[98])->(o0[31],o1[31]) */
static int casadi_f8(const casadi_real** arg, casadi_real** res, casadi_int* iw, casadi_real* w, int mem) {
  casadi_int i;
  casadi_real **res1=res+2, *rr, w2, *w3=w+65, *w4=w+96;
  const casadi_real **arg1=arg+3, *cr, *wr0, *wr1;
  /* #0: @0 = input[1][0] */
  wr0 = arg[1] ? arg[1] : casadi_zeros;
  /* #1: @1 = input[0][0] */
  wr1 = arg[0] ? arg[0] : casadi_zeros;
  /* #2: @2 = input[1][1] */
  w2 = arg[1] ? arg[1][31] : 0;
  /* #3: @3 = (@1*@2) */
  for (i=0, rr=w3, cr=wr1; i<31; ++i) (*rr++)  = ((*cr++)*w2);
  /* #4: @4 = integrate(@0, @3) */
  arg1[0]=wr0;
  arg1[1]=w3;
  res1[0]=w4;
  if (casadi_f9(arg1, res1, iw, w, 0)) return 1;
  /* #5: output[0][0] = @4 */
  casadi_copy(w4, 31, res[0]);
  /* #6: output[1][0] = @1 */
  casadi_copy(wr1, 31, res[1]);
  return 0;
}

